<h2>Artikel</h2><form class="filters"><input type="hidden" name="p" value="items"><input name="q" placeholder="Suche" value="<?=h($_GET['q']??'')?>"><select name="location_id"><option value="">Alle Orte</option><?php foreach($locations as $l):?><option value="<?=h($l['id'])?>" <?=($_GET['location_id']??'')==$l['id']?'selected':''?>><?=h($l['code'].' '.$l['name'])?></option><?php endforeach?></select><select name="container_id"><option value="">Alle Behälter</option><?php foreach($containers as $c):?><option value="<?=h($c['id'])?>" <?=($_GET['container_id']??'')==$c['id']?'selected':''?>><?=h($c['code'].' '.$c['name'])?></option><?php endforeach?></select><select name="category"><option value="">Alle Kategorien</option><?php foreach($categories as $c):?><option <?=($_GET['category']??'')===$c?'selected':''?>><?=h($c)?></option><?php endforeach?></select><select name="tag"><option value="">Alle Tags</option><?php foreach($tags as $t):?><option <?=($_GET['tag']??'')===$t?'selected':''?>><?=h($t)?></option><?php endforeach?></select><select name="sort"><option value="name">Name</option><option value="category">Kategorie</option><option value="location">Ort</option><option value="updated">zuletzt geändert</option></select><button>Suchen</button><a class="button" href="?p=item_form">+ Artikel</a></form><table><tr><th>ID</th><th>Name</th><th>Menge</th><th>Einheit</th><th>Kategorie</th><th>Ort</th><th>Behälter</th><th>Detail</th><th>Tags</th><th>Aktionen</th></tr><?php foreach($items as $i):?><tr><td><?=h($i['id'])?></td><td><?=h($i['name'])?></td><td><?=h($i['quantity'])?></td><td><?=h($i['unit'])?></td><td><?=h($i['category'])?></td><td><?=h($i['location_code'].' '.$i['location_name'])?></td><td><?=h(($i['container_code']??'').' '.($i['container_name']??''))?></td><td><?=h($i['location_detail'])?></td><td><?=h(tags_to_string($i['tags']))?></td><td><a href="?p=item_form&id=<?=h($i['id'])?>">Bearbeiten</a></td></tr><?php endforeach?></table>
